// parity.test.ts — prove the TypeScript engine port reproduces the Phase 0
// goldens EXACTLY. It reuses the same fixtures (../../test/fixtures) and asserts
// against the same committed goldens (../../test/goldens) that the JS harness
// generated. Green = behavioral parity of Rec/Q in TypeScript.

import assert from 'node:assert';
import fs from 'node:fs';
import path from 'node:path';
import { test } from 'node:test';
import { fileURLToPath } from 'node:url';
import { type Ctx, Q, type Task } from '../src/query.js';
import { Rec } from '../src/rec.js';
import { freezeClock } from './support/clock.js';

// Imports hoist; this runs before any test() callback executes, so the engines
// (which read the clock lazily) see the frozen 2026-06-18 baseline.
freezeClock();

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT_TEST = path.resolve(__dirname, '..', '..', 'test');

function loadFixture(name: string): any {
  return JSON.parse(fs.readFileSync(path.join(ROOT_TEST, 'fixtures', name), 'utf8'));
}
// Compare against the committed Phase 0 golden, serialized identically to
// golden.cjs (2-space JSON + trailing newline). Read-only: never writes.
function assertGolden(name: string, value: unknown): void {
  const file = path.join(ROOT_TEST, 'goldens', `${name}.json`);
  const expected = fs.readFileSync(file, 'utf8');
  const actual = `${JSON.stringify(value, null, 2)}\n`;
  assert.strictEqual(actual, expected, `TS port diverges from golden "${name}"`);
}

// ---- Rec (mirrors rec.test.cjs) -------------------------------------------
const recFx = loadFixture('recurrence.json');

test('parity Rec: parse / stringify / summary / compact per rule', () => {
  const out = recFx.rules.map((rule: string) => {
    const parsed = Rec.parse(rule);
    return {
      rule,
      parsed,
      stringify: Rec.stringify(parsed),
      summary: Rec.summary(parsed),
      compact: Rec.compact(parsed),
    };
  });
  assertGolden('rec.rules', out);
});

test('parity Rec: nextOccurrences / next with explicit from + anchor', () => {
  const out = recFx.occurrences.map((c: any) => {
    const occ = Rec.nextOccurrences(c.rule, {
      from: c.from,
      anchor: c.anchor,
      count: c.count,
      inclusive: c.inclusive,
    });
    const n = Rec.next(c.rule, c.from, c.anchor);
    return {
      rule: c.rule,
      from: c.from,
      anchor: c.anchor,
      count: c.count,
      inclusive: c.inclusive,
      occurrences: occ.map(Rec.ymd),
      next: n ? Rec.ymd(n) : null,
    };
  });
  assertGolden('rec.occurrences', out);
});

test('parity Rec: matches for specific dates', () => {
  const out = recFx.matches.map((c: any) => ({
    rule: c.rule,
    anchor: c.anchor,
    results: c.dates.map((dStr: string) => ({
      date: dStr,
      matches: Rec.matches(
        Rec.parseYMD(dStr) as Date,
        Rec.parse(c.rule) as NonNullable<ReturnType<typeof Rec.parse>>,
        Rec.parseYMD(c.anchor) as Date,
      ),
    })),
  }));
  assertGolden('rec.matches', out);
});

test('parity Rec: date helpers', () => {
  const h = recFx.dateHelpers;
  assertGolden('rec.dateHelpers', {
    ymd: h.ymd.map((s: string) => Rec.ymd(Rec.parseYMD(s) as Date)),
    addDays: h.addDays.map(([s, n]: [string, number]) =>
      Rec.ymd(Rec.addDays(Rec.parseYMD(s) as Date, n)),
    ),
    daysBetween: h.daysBetween.map(([a, b]: [string, string]) =>
      Rec.daysBetween(Rec.parseYMD(a) as Date, Rec.parseYMD(b) as Date),
    ),
    ordSuffix: h.ordSuffix.map((n: number) => n + Rec.ordSuffix(n)),
  });
});

// ---- Q (mirrors query.test.cjs) -------------------------------------------
const tasks = loadFixture('corpus.tasks.json') as Task[];
const projects = loadFixture('corpus.projects.json');
const labels = loadFixture('corpus.labels.json');
const queries = loadFixture('queries.json').queries as string[];
const ctx: Ctx = { tasks, projects, labels, weekStart: 1 };

test('parity Q: parse + build round-trip', () => {
  const out = queries.map((q) => {
    const parsed = Q.parse(q);
    return { query: q, terms: parsed.terms, rebuilt: Q.build(parsed.terms) };
  });
  assertGolden('query.parse', out);
});

test('parity Q: run over corpus -> matching ids', () => {
  const out = queries.map((q) => ({
    query: q,
    matches: Q.run(q, ctx).map((t) => t.id),
  }));
  assertGolden('query.run', out);
});

test('parity Q: dueDelta + slug helpers', () => {
  assertGolden('query.helpers', {
    dueDelta: tasks.map((t) => ({ id: t.id, due: t.due, delta: Q.dueDelta(t) })),
    slug: ['Work', 'My Project!', 'a-b-c', '  Spaces  ', 'ÜberCafé'].map((s) => ({
      in: s,
      out: Q.slug(s),
    })),
  });
});

// query.ts — TypeScript port of frontend/js/query.js. Behavior intended identical
// (parity-tested against the Phase 0 goldens); the only changes are window.Q ->
// exports, the bare global `Rec` -> an import, and light types. Grammar unchanged
// — see the original header.

import { Rec } from './rec.js';

export interface Task {
  id?: string;
  title?: string;
  notes?: string;
  projectId?: string;
  parentId?: string | null;
  labels?: string[];
  done?: boolean;
  due?: string | null;
  reminder?: string | null;
  recurrence?: string | null;
  priority?: number;
  size?: number;
  [k: string]: unknown;
}
export interface Project {
  id: string;
  name: string;
  [k: string]: unknown;
}
export interface Label {
  id: string;
  name: string;
  [k: string]: unknown;
}
export interface Ctx {
  tasks?: Task[];
  projects?: Project[];
  labels?: Label[];
  weekStart?: number;
}
export interface Term {
  field: string;
  value: string;
  neg: boolean;
}
export interface ParsedQuery {
  terms: Term[];
  ok: boolean;
}

const today = () => Rec.startOfDay(new Date());

// tokenize respecting quotes
function tokenize(str: string): string[] {
  const out: string[] = [];
  const re = /"([^"]*)"|(\S+)/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(str))) out.push(m[1] !== undefined ? `"${m[1]}"` : m[2]);
  return out;
}

function parse(str: string | null | undefined): ParsedQuery {
  const terms: Term[] = [];
  if (!str || !str.trim()) return { terms, ok: true };
  for (let tok of tokenize(str)) {
    let neg = false;
    if (tok.startsWith('-') && tok.length > 1 && tok.indexOf(':') > 0) {
      neg = true;
      tok = tok.slice(1);
    }
    const qi = tok.indexOf(':');
    if (qi > 0 && !tok.startsWith('"')) {
      const field = tok.slice(0, qi).toLowerCase();
      const value = tok.slice(qi + 1).toLowerCase();
      terms.push({ field, value, neg });
    } else {
      terms.push({ field: 'text', value: tok.replace(/^"|"$/g, '').toLowerCase(), neg });
    }
  }
  return { terms, ok: true };
}

// resolve a project token (id or slug of name) -> set of matching project ids only
// (exact: subprojects are NOT included, so a parent's view/count shows just its own tasks)
function resolveProjects(value: string, ctx: Ctx): Set<string> {
  const projects = ctx.projects || [];
  const match = projects.filter(
    (p) => p.id === value || slug(p.name) === slug(value) || slug(p.name).includes(slug(value)),
  );
  return new Set(match.map((p) => p.id));
}
function slug(s: string | null | undefined): string {
  return String(s || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '');
}

function dueDelta(task: Task): number | null {
  // days from today to due (negative = overdue). null if no due.
  if (!task.due) return null;
  return Rec.daysBetween(today(), Rec.parseYMD(task.due) as Date);
}
function remDelta(task: Task): number | null {
  if (!task.reminder) return null;
  // reminder may be a 'YYYY-MM-DDTHH:MM' timestamp; query filters are day-grained.
  return Rec.daysBetween(today(), Rec.parseYMD(task.reminder.slice(0, 10)) as Date);
}

function cmpDate(delta: number | null, op: string): boolean {
  // op like "<7d", "<=3d", ">0d", "=0d"
  const mm = op.match(/^(<=|>=|<|>|=)(-?\d+)d$/);
  if (!mm || delta === null) return false;
  const o = mm[1];
  const n = +mm[2];
  switch (o) {
    case '<':
      return delta < n;
    case '>':
      return delta > n;
    case '<=':
      return delta <= n;
    case '>=':
      return delta >= n;
    case '=':
      return delta === n;
  }
  return false;
}

// ---- weekday window (due:su, due:mwf, …) ----------------------------------
// letter -> JS getDay() (0=Sun … 6=Sat)
const DOW: Record<string, number> = { u: 0, m: 1, t: 2, w: 3, r: 4, f: 5, s: 6 };
function weekdaySet(v: string): Set<number> {
  const s = new Set<number>();
  for (const c of String(v || '')) {
    if (c in DOW) s.add(DOW[c]);
  }
  return s;
}
// The active cycle's dates for the selected weekdays. weekStart: 0=Sun..6=Sat (default Mon).
// Window = this week's selected days, rolling to next week once we're past the last one.
function dueWindow(daySet: Set<number>, weekStart?: number): string[] {
  weekStart = weekStart == null ? 1 : weekStart;
  if (!daySet.size) return [];
  const now = today(); // Rec.startOfDay(new Date())
  const back = (now.getDay() - weekStart + 7) % 7; // days since the week start
  const start = Rec.addDays(now, -back);
  let dates = [...daySet].map((d) => Rec.addDays(start, (d - (weekStart as number) + 7) % 7));
  const last = dates.reduce((a, b) => (a > b ? a : b));
  if (now > last) dates = dates.map((d) => Rec.addDays(d, 7)); // past the window -> next week
  return dates.map(Rec.ymd);
}

function evalTerm(task: Task, t: Term, ctx: Ctx): boolean {
  const labelsOf = task.labels || [];
  let res = false;
  switch (t.field) {
    case 'text':
      res =
        (task.title || '').toLowerCase().includes(t.value) ||
        (task.notes || '').toLowerCase().includes(t.value);
      break;
    case 'project': {
      const ids = resolveProjects(t.value, ctx);
      res = ids.has(task.projectId as string);
      break;
    }
    case 'label': {
      const wants = t.value.split(',').map(slug);
      res = labelsOf.some((lid) => {
        const lab = (ctx.labels || []).find((l) => l.id === lid);
        return lab && wants.includes(slug(lab.name));
      });
      break;
    }
    case 'status': {
      const d = dueDelta(task);
      if (t.value === 'done') res = !!task.done;
      else if (t.value === 'open') res = !task.done;
      else if (t.value === 'overdue') res = !task.done && d !== null && d < 0;
      else if (t.value === 'today') res = !task.done && d === 0;
      break;
    }
    case 'due': {
      const d = dueDelta(task);
      if (t.value === 'none') res = d === null;
      else if (t.value === 'set') res = d !== null;
      else if (t.value === 'today') res = d === 0;
      else if (t.value === 'tomorrow') res = d === 1;
      else if (t.value === 'overdue') res = d !== null && d < 0;
      else if (t.value === 'week') res = d !== null && d >= 0 && d <= 7;
      else if (t.value === 'month') res = d !== null && d >= 0 && d <= 31;
      else if (/^[mtwrfsu]+$/.test(t.value))
        res =
          !!task.due &&
          dueWindow(weekdaySet(t.value), ctx.weekStart).includes(task.due.slice(0, 10));
      else res = cmpDate(d, t.value);
      break;
    }
    case 'reminder': {
      const d = remDelta(task);
      if (t.value === 'none') res = d === null;
      else if (t.value === 'set') res = d !== null;
      else if (t.value === 'today') res = d === 0;
      else if (t.value === 'overdue') res = d !== null && d < 0;
      else res = cmpDate(d, t.value);
      break;
    }
    case 'recurring':
      res = t.value === 'true' ? !!task.recurrence : !task.recurrence;
      break;
    case 'is':
      if (t.value === 'subtask') res = !!task.parentId;
      else if (t.value === 'task') res = !task.parentId;
      else if (t.value === 'recurring') res = !!task.recurrence;
      else if (t.value === 'done') res = !!task.done;
      else if (t.value === 'open') res = !task.done;
      break;
    case 'has':
      if (t.value === 'subtasks') res = (ctx.tasks || []).some((x) => x.parentId === task.id);
      else if (t.value === 'label') res = labelsOf.length > 0;
      else if (t.value === 'no-labels') res = labelsOf.length === 0;
      else if (t.value === 'due') res = !!task.due;
      break;
    default:
      // unknown field -> treat as text match on "field:value"
      res = (task.title || '').toLowerCase().includes(`${t.field}:${t.value}`);
  }
  return t.neg ? !res : res;
}

function evaluate(task: Task, query: string | ParsedQuery, ctx: Ctx): boolean {
  const q = typeof query === 'string' ? parse(query) : query;
  if (!q.terms.length) return true;
  return q.terms.every((t) => evalTerm(task, t, ctx));
}

// run query over the task list -> matching tasks (flat)
function run(query: string | ParsedQuery, ctx: Ctx): Task[] {
  return (ctx.tasks || []).filter((t) => evaluate(t, query, ctx));
}

// ---- builder helpers: structured <-> string ---------------
// We keep builder state as an array of {field,value,neg}; string is the join.
function termToString(t: Term): string {
  const body =
    t.field === 'text' ? (/\s/.test(t.value) ? `"${t.value}"` : t.value) : `${t.field}:${t.value}`;
  return (t.neg ? '-' : '') + body;
}
function build(terms: Term[]): string {
  return terms.map(termToString).join(' ');
}

export const Q = { parse, evaluate, run, build, termToString, tokenize, slug, dueDelta };
export default Q;
export { parse, evaluate, run, build, termToString, tokenize, slug, dueDelta };

// rec.ts — TypeScript port of frontend/js/recurrence.js (pure functions).
// Behavior is intended to be byte-for-byte identical (parity-tested against the
// Phase 0 goldens); only the wrapper changed (window.Rec -> exports) plus light
// types. Supported syntax is unchanged — see the original header.

export type RuleType = 'daily' | 'weekly' | 'monthly-day' | 'monthly-weekday' | 'invalid';

export interface Rule {
  type: RuleType;
  interval?: number;
  days?: number[] | null;
  day?: number | null;
  ord?: number;
  weekday?: number;
  raw?: string;
}

export interface OccurrenceOpts {
  anchor?: string | Date;
  from?: string | Date;
  count?: number;
  inclusive?: boolean;
}

const WD = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];
const WD_FULL = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
const ORD: Record<string, number> = { '1st': 1, '2nd': 2, '3rd': 3, '4th': 4, '5th': 5, last: -1 };
const ORD_NAME: Record<number, string> = {
  1: '1st',
  2: '2nd',
  3: '3rd',
  4: '4th',
  5: '5th',
  '-1': 'last',
};

function pad(n: number): string {
  return String(n).padStart(2, '0');
}
export function ymd(d: Date): string {
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}
export function parseYMD(s: string | null | undefined): Date | null {
  if (!s) return null;
  const [y, m, d] = s.split('-').map(Number);
  return new Date(y, m - 1, d);
}
export function startOfDay(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth(), d.getDate());
}
export function addDays(d: Date, n: number): Date {
  const x = new Date(d);
  x.setDate(x.getDate() + n);
  return x;
}
export function daysBetween(a: Date, b: Date): number {
  return Math.round((+startOfDay(b) - +startOfDay(a)) / 86400000);
}
function sameDay(a: Date, b: Date): boolean {
  return ymd(a) === ymd(b);
}

// ---- parse -------------------------------------------------
export function parse(str: string | null | undefined): Rule | null {
  if (!str) return null;
  const s = str.trim().toLowerCase().replace(/\s+/g, ' ');
  let m: RegExpMatchArray | null;

  if (s === 'daily' || s === 'every day') return { type: 'daily', interval: 1 };

  if ((m = s.match(/^every (\d+) days?$/))) return { type: 'daily', interval: +m[1] };

  // weekly on days / every N weeks on days
  if ((m = s.match(/^weekly on (.+)$/))) return mkWeekly(1, m[1]);
  if ((m = s.match(/^every (\d+) weeks? on (.+)$/))) return mkWeekly(+m[1], m[2]);
  if ((m = s.match(/^every (\d+) weeks?$/))) return { type: 'weekly', interval: +m[1], days: null };

  // monthly on day D
  if ((m = s.match(/^monthly on day (\d+)$/)))
    return { type: 'monthly-day', interval: 1, day: clampDay(+m[1]) };
  if ((m = s.match(/^every (\d+) months? on day (\d+)$/)))
    return { type: 'monthly-day', interval: +m[1], day: clampDay(+m[2]) };

  // monthly on Nth weekday
  if ((m = s.match(/^monthly on (1st|2nd|3rd|4th|5th|last) (mon|tue|wed|thu|fri|sat|sun)$/)))
    return { type: 'monthly-weekday', interval: 1, ord: ORD[m[1]], weekday: WD.indexOf(m[2]) };
  if (
    (m = s.match(
      /^every (\d+) months? on (1st|2nd|3rd|4th|5th|last) (mon|tue|wed|thu|fri|sat|sun)$/,
    ))
  )
    return { type: 'monthly-weekday', interval: +m[1], ord: ORD[m[2]], weekday: WD.indexOf(m[3]) };

  if ((m = s.match(/^every (\d+) months?$/)))
    return { type: 'monthly-day', interval: +m[1], day: null };

  return { type: 'invalid', raw: str };
}

function clampDay(d: number): number {
  return Math.min(31, Math.max(1, d));
}

function mkWeekly(interval: number, daysStr: string): Rule {
  const days = daysStr
    .split(/[ ,]+/)
    .map((x) => WD.indexOf(x.trim()))
    .filter((i) => i >= 0)
    .sort((a, b) => a - b);
  if (!days.length) return { type: 'invalid', raw: `weekly on ${daysStr}` };
  return { type: 'weekly', interval, days };
}

// ---- stringify (canonical) --------------------------------
export function stringify(r: Rule | null): string {
  if (!r || r.type === 'invalid') return '';
  switch (r.type) {
    case 'daily':
      return r.interval === 1 ? 'daily' : `every ${r.interval} days`;
    case 'weekly': {
      const dd = r.days && r.days.length ? r.days.map((i) => WD[i]).join(',') : null;
      if (r.interval === 1) return dd ? `weekly on ${dd}` : 'weekly on mon';
      return dd ? `every ${r.interval} weeks on ${dd}` : `every ${r.interval} weeks`;
    }
    case 'monthly-day': {
      const d = r.day || 1;
      return r.interval === 1 ? `monthly on day ${d}` : `every ${r.interval} months on day ${d}`;
    }
    case 'monthly-weekday': {
      const o = ORD_NAME[r.ord as number];
      const w = WD[r.weekday as number];
      return r.interval === 1 ? `monthly on ${o} ${w}` : `every ${r.interval} months on ${o} ${w}`;
    }
  }
}

// ---- human summary ----------------------------------------
export function summary(strOrObj: string | Rule | null): string {
  const r = typeof strOrObj === 'string' ? parse(strOrObj) : strOrObj;
  if (!r) return '';
  if (r.type === 'invalid') return 'invalid pattern';
  switch (r.type) {
    case 'daily':
      return r.interval === 1 ? 'Every day' : `Every ${r.interval} days`;
    case 'weekly': {
      const names = r.days && r.days.length ? r.days.map((i) => WD_FULL[i]).join(', ') : '—';
      if (r.interval === 1) return `Weekly on ${names}`;
      return r.days && r.days.length
        ? `Every ${r.interval} weeks on ${names}`
        : `Every ${r.interval} weeks`;
    }
    case 'monthly-day': {
      const d = r.day;
      if (!d) return `Every ${r.interval} months`;
      const suf = ordSuffix(d);
      return r.interval === 1
        ? `Monthly on the ${d}${suf}`
        : `Every ${r.interval} months on the ${d}${suf}`;
    }
    case 'monthly-weekday': {
      const ord = r.ord as number;
      const o = ord === -1 ? 'last' : ord + ordSuffix(ord);
      const w = WD_FULL[r.weekday as number];
      return r.interval === 1
        ? `Monthly on the ${o} ${w}`
        : `Every ${r.interval} months on the ${o} ${w}`;
    }
  }
}
export function ordSuffix(n: number): string {
  const s = ['th', 'st', 'nd', 'rd'];
  const v = n % 100;
  return s[(v - 20) % 10] || s[v] || s[0];
}

// compact one-line label for dense rows
export function compact(strOrObj: string | Rule | null): string {
  const r = typeof strOrObj === 'string' ? parse(strOrObj) : strOrObj;
  if (!r || r.type === 'invalid') return '';
  const A = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];
  switch (r.type) {
    case 'daily':
      return r.interval === 1 ? 'daily' : `${r.interval}d`;
    case 'weekly': {
      const dd = r.days && r.days.length ? r.days.map((i) => A[i]).join('·') : '—';
      return r.interval === 1 ? dd : `${dd}/${r.interval}w`;
    }
    case 'monthly-day':
      if (!r.day) return `${r.interval}mo`;
      return r.interval === 1 ? `day ${r.day}` : `day ${r.day}/${r.interval}mo`;
    case 'monthly-weekday': {
      const ord = r.ord as number;
      const o = ord === -1 ? 'last' : ord + ordSuffix(ord);
      const w = A[r.weekday as number];
      return r.interval === 1 ? `${o} ${w}` : `${o} ${w}/${r.interval}mo`;
    }
  }
}

// ---- occurrence matching ----------------------------------
function nthWeekdayOfMonth(year: number, month: number, weekday: number, ord: number): Date | null {
  if (ord === -1) {
    const last = new Date(year, month + 1, 0);
    const back = (last.getDay() - weekday + 7) % 7;
    return new Date(year, month, last.getDate() - back);
  }
  const first = new Date(year, month, 1);
  const offset = (weekday - first.getDay() + 7) % 7;
  const day = 1 + offset + (ord - 1) * 7;
  const dim = new Date(year, month + 1, 0).getDate();
  if (day > dim) return null;
  return new Date(year, month, day);
}

export function matches(date: Date, r: Rule, anchor?: Date): boolean {
  date = startOfDay(date);
  anchor = anchor ? startOfDay(anchor) : date;
  if (date < anchor) return false;
  switch (r.type) {
    case 'daily': {
      const n = r.interval || 1;
      return daysBetween(anchor, date) % n === 0;
    }
    case 'weekly': {
      const n = r.interval || 1;
      const days = r.days && r.days.length ? r.days : [anchor.getDay()];
      if (!days.includes(date.getDay())) return false;
      // week phase: weeks since anchor's Sunday
      const aWeek = weekIndex(anchor);
      const dWeek = weekIndex(date);
      return (dWeek - aWeek) % n === 0;
    }
    case 'monthly-day': {
      const n = r.interval || 1;
      if (monthsBetween(anchor, date) % n !== 0) return false;
      const dim = new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
      const target = r.day ? Math.min(r.day, dim) : Math.min(anchor.getDate(), dim);
      return date.getDate() === target;
    }
    case 'monthly-weekday': {
      const n = r.interval || 1;
      if (monthsBetween(anchor, date) % n !== 0) return false;
      const occ = nthWeekdayOfMonth(
        date.getFullYear(),
        date.getMonth(),
        r.weekday as number,
        r.ord as number,
      );
      return !!occ && sameDay(occ, date);
    }
  }
  return false;
}
function weekIndex(d: Date): number {
  return Math.floor(daysBetween(new Date(1970, 0, 4), d) / 7); // 1970-01-04 = Sunday
}
function monthsBetween(a: Date, b: Date): number {
  return (b.getFullYear() - a.getFullYear()) * 12 + (b.getMonth() - a.getMonth());
}

// ---- next N occurrences from a date (exclusive of `from` by default)
export function nextOccurrences(strOrObj: string | Rule | null, opts?: OccurrenceOpts): Date[] {
  opts = opts || {};
  const r = typeof strOrObj === 'string' ? parse(strOrObj) : strOrObj;
  if (!r || r.type === 'invalid') return [];
  const anchorD = opts.anchor
    ? typeof opts.anchor === 'string'
      ? parseYMD(opts.anchor)
      : opts.anchor
    : new Date();
  const fromD = opts.from
    ? typeof opts.from === 'string'
      ? parseYMD(opts.from)
      : opts.from
    : new Date();
  const count = opts.count || 3;
  const inclusive = !!opts.inclusive;
  const out: Date[] = [];
  let cur = startOfDay(fromD as Date);
  if (!inclusive) cur = addDays(cur, 1);
  let guard = 0;
  const cap = 366 * 6;
  while (out.length < count && guard < cap) {
    if (matches(cur, r, anchorD as Date)) out.push(new Date(cur));
    cur = addDays(cur, 1);
    guard++;
  }
  return out;
}

// next single occurrence strictly after `from`
export function next(
  strOrObj: string | Rule | null,
  from?: string | Date,
  anchor?: string | Date,
): Date | null {
  const r = nextOccurrences(strOrObj, { from, anchor: anchor || from, count: 1 });
  return r[0] || null;
}

